import{_ as t,o,c as r,a0 as s}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Browser Support Matrix","description":"","frontmatter":{},"headers":[],"relativePath":"browser-support.md","filePath":"browser-support.md","lastUpdated":1784187737000}'),a={name:"browser-support.md"};function n(i,e,d,c,l,h){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="browser-support-matrix" tabindex="-1">Browser Support Matrix <a class="header-anchor" href="#browser-support-matrix" aria-label="Permalink to &quot;Browser Support Matrix&quot;">​</a></h1><h2 id="supported-browsers" tabindex="-1">Supported browsers <a class="header-anchor" href="#supported-browsers" aria-label="Permalink to &quot;Supported browsers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Browser</th><th>Minimum version</th><th>Notes</th></tr></thead><tbody><tr><td>Chrome / Edge (Chromium)</td><td>111+</td><td>Baseline for <code>srcdoc</code>, <code>sandbox</code>, and CSP <code>nonce</code> on injected elements.</td></tr><tr><td>Firefox</td><td>115 (ESR)+</td><td>Full support.</td></tr><tr><td>Safari</td><td>16.4+</td><td><code>srcdoc</code> and <code>sandbox</code> supported; verify CSP <code>nonce</code> propagation into <code>srcdoc</code> documents before relying on it (historically inconsistent across engines).</td></tr></tbody></table><p>These versions reflect the browser engines targeted by the library&#39;s build output (<code>ES2020</code>+, per <code>@vue/tsconfig</code>) and by Vue 3 itself — not necessarily the full extent of what works. If your organization needs to support older browsers, you will likely need additional polyfills independent of this library.</p><h2 id="what-supported-means-here" tabindex="-1">What &quot;supported&quot; means here <a class="header-anchor" href="#what-supported-means-here" aria-label="Permalink to &quot;What &quot;supported&quot; means here&quot;">​</a></h2><ul><li>The <strong>library&#39;s own code</strong> (composables, utilities, component logic) runs correctly.</li><li>The <strong>injection primitives</strong> (<code>&lt;style&gt;</code>, <code>&lt;link rel=&quot;stylesheet&quot;&gt;</code>, <code>&lt;script&gt;</code>, <code>&lt;script src&gt;</code>) behave the same way jQuery/vanilla DOM APIs would on that browser — this library does not add browser-specific workarounds beyond what&#39;s noted below.</li><li><code>sandbox</code> attribute semantics follow the <a href="https://html.spec.whatwg.org/multipage/iframe-embed-object.html#attr-iframe-sandbox" target="_blank" rel="noreferrer">HTML Living Standard</a> as implemented by each engine; enforcement details (e.g. exact <code>allow-*</code> token behavior) are the browser&#39;s responsibility, not this library&#39;s.</li></ul><h2 id="known-engine-differences" tabindex="-1">Known engine differences <a class="header-anchor" href="#known-engine-differences" aria-label="Permalink to &quot;Known engine differences&quot;">​</a></h2><ul><li><strong>CSP <code>nonce</code> on injected elements</strong> (<code>InjectionOptions.nonce</code>): nonce propagation into dynamically created <code>&lt;style&gt;</code>/<code>&lt;script&gt;</code> elements inside a <code>srcdoc</code> document has historically had inconsistent behavior across engines when the document itself sets a strict CSP via <code>&lt;meta http-equiv=&quot;Content-Security-Policy&quot;&gt;</code>. If you rely on <code>nonce</code>, verify against your specific target browsers and CSP configuration — this is tracked as a real-browser test gap, not yet covered by <a href="/enterprise-readiness#phase-4--real-browser-e2e-suite-sds-phase-9-1-2-weeks">automated E2E testing</a>.</li><li><strong><code>ResizeObserver</code></strong> (used by the proposed auto-height feature in <a href="/feature-recommendations"><code>FEATURE_RECOMMENDATIONS.md</code></a> #4, not yet implemented): supported in all browsers listed above; no polyfill is planned since the minimum versions already cover it natively.</li></ul><h2 id="verification-status" tabindex="-1">Verification status <a class="header-anchor" href="#verification-status" aria-label="Permalink to &quot;Verification status&quot;">​</a></h2><p>⚠️ The matrix above reflects the <strong>targeted</strong> support surface based on the build configuration and underlying platform APIs used. It is not yet backed by an automated cross-browser test suite — that is <a href="/enterprise-readiness#phase-4--real-browser-e2e-suite-sds-phase-9-1-2-weeks">Phase 4 of the Enterprise Readiness plan</a> (Playwright across Chromium/Firefox/WebKit). Until that lands, treat this matrix as a documented intent rather than a tested guarantee, and file an issue using the <a href="https://github.com/enterprise/vue-iframe-wrapper/issues/new?template=bug_report.md" target="_blank" rel="noreferrer">bug report template</a> if you find a discrepancy on a listed browser/version.</p><h2 id="node-js-build-time-only" tabindex="-1">Node.js (build-time only) <a class="header-anchor" href="#node-js-build-time-only" aria-label="Permalink to &quot;Node.js (build-time only)&quot;">​</a></h2><p>Node.js is only relevant for building the library and running its test suite — none of this ships to end users&#39; browsers.</p><table tabindex="0"><thead><tr><th>Requirement</th><th>Version</th></tr></thead><tbody><tr><td>Node.js</td><td><code>&gt;= 20.11.0</code></td></tr><tr><td>npm</td><td><code>&gt;= 10.0.0</code></td></tr></tbody></table><p>See <code>engines</code> in <code>package.json</code>.</p>',14)])])}const b=t(a,[["render",n]]);export{p as __pageData,b as default};
